import pytest

from typing import Dict, List, Any

def topological_sort(graph: Dict[Any, List[Any]]) -> List[Any]:
    visited = set()
    result = []
    def dfs(node):
        if node in visited:
            return
        visited.add(node)
        for neighbor in graph.get(node, []):
            dfs(neighbor)
        result.append(node)
    for node in graph:
        dfs(node)
    return result[::-1]


class TestTopologicalSort:
    def test_empty_graph(self):
        """Happy path: Empty graph returns empty list."""
        assert topological_sort({}) == []

    def test_single_node(self):
        """Happy path: Single node with no edges."""
        assert topological_sort({'A': []}) == ['A']

    def test_simple_chain(self):
        """Happy path: Simple directed chain A -> B."""
        graph = {'A': ['B'], 'B': []}
        assert topological_sort(graph) == ['A', 'B']

    def test_dag_with_multiple_parents(self):
        """Happy path: DAG where C has two parents A and B.
        Order depends on dict iteration (insertion order in Python 3.7+)."""
        graph = {'A': ['C'], 'B': ['C'], 'C': []}
        # DFS starts with 'A' (append 'C' then 'A'), then 'B' (skip 'C', append 'B'),
        # result=['C', 'A', 'B'], reverse to ['B', 'A', 'C']
        assert topological_sort(graph) == ['B', 'A', 'C']

    def test_disconnected_components(self):
        """Happy path: Disconnected components."""
        graph = {'A': ['B'], 'C': ['D'], 'B': [], 'D': []}
        # Assuming insertion order A,B,C,D: DFS A (append B,A), DFS C (append D,C),
        # result=['B','A','D','C'], reverse ['C','D','A','B']
        expected = ['C', 'D', 'A', 'B']
        assert topological_sort(graph) == expected

    def test_nodes_only_in_values(self):
        """Edge case: Nodes present only as neighbors (not keys) are included if reachable."""
        graph = {'A': ['B', 'C'], 'B': ['D']}
        # 'C' and 'D' not keys, but reached: DFS A, DFS B, DFS D (append D), append B,
        # DFS C (append C), append A; result=['D','B','C','A'], reverse ['A','B','C','D']
        # Note: Order of neighbors in list affects: first B then C, so B before C in post-order.
        assert topological_sort(graph) == ['A', 'B', 'C', 'D']

    def test_self_loop(self):
        """Edge case: Self-loop does not cause infinite recursion (due to visited)."""
        graph = {'A': ['A']}
        assert topological_sort(graph) == ['A']

    def test_cycle(self):
        """Edge case: Cycle exists (no valid topo sort), but function does not crash
        and produces an order (though invalid for topo)."""
        graph = {'A': ['B'], 'B': ['A']}
        # DFS A, DFS B (skip A), append B, append A; reverse ['A', 'B']
        result = topological_sort(graph)
        assert result == ['A', 'B']  # Runs without error, includes all nodes

    def test_no_edges_multiple_nodes(self):
        """Edge case: Multiple nodes, no edges."""
        graph = {'A': [], 'B': [], 'C': []}
        # DFS each: append A, B, C; reverse ['C', 'B', 'A'] (insertion order)
        assert topological_sort(graph) == ['C', 'B', 'A']

    def test_invalid_input_not_dict(self):
        """Error case: Input is not a dict -> TypeError on iteration."""
        with pytest.raises(TypeError, match=".* object is not iterable"):
            topological_sort("not a dict")

    def test_invalid_values_not_iterable(self):
        """Error case: Graph values are not iterables -> TypeError on neighbor iteration."""
        graph = {'A': "not a list"}
        with pytest.raises(TypeError, match=".* object is not iterable"):
            topological_sort(graph)

    def test_mixed_invalid(self):
        """Error case: Graph with some invalid values."""
        graph = {'A': ['B'], 'C': 123}  # 'C' value not iterable
        with pytest.raises(TypeError, match=".* object is not iterable"):
            topological_sort(graph)
